import style from './Contact.module.css'
import { Link } from 'react-router-dom';
import { EmailJSResponseStatusmailjs } from '@emailjs/browser';
import React, { useRef } from 'react';

function Contact() {
    const form = useRef();

    const sendEmail = (e) => {
        e.preventDefault();

        EmailJSResponseStatusmailjs.sendForm(
            'shdq190109',
            'template_bdo05xo',
            form.current,
            'K4NTdgElNQ3N4cQ9H'
        ).then((result) => {
            alert("Pesan Berhasil dikirim!");
            console.log(result.text);
            e.target.reset();
        }, (error) => {
            alert("Gagal mengirim pesan.");
            console.log(error.text);
        });
    };

    return (
        <div className={style.contactpage}>
            <header className={style.header}>
                <h1 className={style.logo}>MSHDQ</h1>
                <nav className={style.nav}>
                    <Link to="/" className={style.link}>HOME</Link>
                    <Link to="/about" className={style.link}>ABOUT</Link>
                    <Link to="/service" className={style.link}>SERVICE</Link>
                    <Link to="/portofolio" className={style.link}>PORTOFOLIO</Link>
                    <Link to="/blog" className={style.link}>BLOG</Link>
                    <Link to="/contact" className={style.link}>CONTACT</Link>
                </nav>
            </header>

            <section className={style.contact_section}>
                <h1>Contact Me</h1>
                <p>If you’d like to collaborate or just say hi, feel free to send a message!</p>

                <form className={style.contact_form}>
                    <input type="text" name="from_name" placeholder="Your Name" required />
                    <input type="email" placeholder="Your Email" required />
                    <textarea placeholder="Your Message" rows="6" required></textarea>
                    <button type="submit">Send Message</button>
                </form>
            </section>

            <footer className={style.footer}>
                &copy; 2025 MSHDQ. All rights reserved.
            </footer>
        </div>
    )
}

export default Contact;
